uldades][]" value="<?=e($value)?>" <?=in_array($value,$difficulty['selected'],true)?'checked':''?> <?=$chosen?'':'disabled'?> <?=!$canEdit?'disabled':''?>> <span><?=e($label)?></span></label><?php endforeach;?><input id="difficulty-other-<?=e($a['id'])?>" class="student-field other-detail" name="alunos[<?=e($a['id'])?>][dificuldades_outros]" value="<?=e($difficulty['other'])?>" placeholder="Especifique outros" <?=($chosen&&in_array('OUTROS',$difficulty['selected'],true))?'':'disabled'?> <?=!$canEdit?'readonly':''?>></fieldset></td><td data-label="Medidas adotadas"><fieldset class="student-choice-list"><legend class="sr-only">Medidas para <?=e($a['nome_completo'])?></legend><?php foreach($studentMeasureOptions as$value=>$label):?><label><input class="student-field <?=$value==='OUTROS'?'other-toggle':''?>" <?=$value==='OUTROS'?'data-other-target="measure-other-'.e($a['id']).'"':''?> type="checkbox" name="alunos[<?=e($a['id'])?>][intervencoes][]" value="<?=e($value)?>" <?=in_array($value,$measures['selected'],true)?'checked':''?> <?=$chosen?'':'disabled'?> <?=!$canEdit?'disabled':''?>> <span><?=e($label)?></span></label><?php endforeach;?><input id="measure-other-<?=e($a['id'])?>" class="student-field other-detail" name="alunos[<?=e($a['id'])?>][intervencoes_outros]" value="<?=e($measures['other'])?>" placeholder="Especifique outros" <?=($chosen&&in_array('OUTROS',$measures['selected'],true))?'':'disabled'?> <?=!$canEdit?'readonly':''?>></fieldset></td><td data-label="Observações"><textarea class="student-field student-note" aria-label="Observações sobre <?=e($a['nome_completo'])?>" name="alunos[<?=e($a['id'])?>][observacao]" placeholder="Observações sobre o aluno" <?=$chosen?'':'disabled'?> <?=!$canEdit?'readonly':''?>><?=e($x['observacao']??'')?></textarea></td></tr><?php endforeach;?></tbody></table></div><?php elseif(!$apiError):?><div class="empty-state compact"><p>Nenhum aluno encontrado nesta turma.</p></div><?php endif;?><?php if($canEdit):?><div class="actions